#include<bits/stdc++.h>
using namespace std;
int n,a[110],s[110];
int main()
{
    scanf("%d",&n);
    int sum=0;
    for(int i=1;i<=n;i++)
    {
        scanf("%d",&a[i]);
        sum+=a[i];
    }
    sum/=n;
    for(int i=1;i<=n;i++)
    {
        a[i]-=sum;
        s[i]=s[i-1]+a[i];
    }
    sort(s+1,s+1+n);
    int ans=0;
    for(int i=1;i<=n;i++)
    {
        ans+=abs(s[i]-s[n/2+1]);
    }
    printf("%d",ans);
    return 0;
}
